import { useState, useEffect } from "react"
import "./index.css"

// Define the structure for a todo item
interface TodoItem {
  id: number | string
  text: string
  completed: boolean
}

// Custom hook to interact with the /api/items endpoint
function useTodos() {
  const { data, loading, error, create, update, remove } = useApi<TodoItem>("todos")

  useEffect(() => {
    if (!loading && !error) {
      console.log("Todos loaded:", data)
    }
}, [data, loading, error])

return { todos: data, loading, error, create, update, remove }
}

// Todo Item Component
function TodoItem({ todo }: { todo: TodoItem }) {
  const toggle = async () => {
  if (todo.completed) {
    await api.put<TodoItem>(`/api/todos/${todo.id}`, { ...todo, completed: false })
  } else {
  await api.put<TodoItem>(`/api/todos/${todo.id}`, { ...todo, completed: true })
}

return (
  <div className={`flex items-center justify-between p-3 border-b ${todo.completed ? 'bg-gray-50' : ''} transition duration-150 ${todo.completed ? 'line-through text-gray-400' : 'text-gray-800'} focus:ring-2 focus:ring-indigo-500'}`}
  onClick={toggle}
>
  <input
  type="checkbox"
  checked={todo.completed}
  readOnly
/>
<span className="flex-grow cursor-pointer" onClick={toggle}>
  {todo.text}
</span>

<button
  onClick={(e) => { e.stopPropagation(); api.delete(`/api/todos/${todo.id}`) }}
className="p-2 text-red-500 hover:bg-red-50 hover:ring-2 hover:ring-red-100 transition duration-150"
aria-label={`Delete ${todo.text}`}
disabled={!todo.text}
>
  &times;
</button>
)}

// Todo List Component
function TodoList({ todos }: { todos: TodoItem[] }) {
  if (todos.length === 0) {
  return (
  <div className="p-6 bg-white rounded-xl shadow-sm border border-gray-100">
  <h3 className="text-xl font-semibold mb-2 text-indigo-700">No tasks yet</h3>
<p className="text-gray-500">Looks like you have an empty list. Time to get organized!</p>
</div>
)}

return (
<div className="space-y-3 p-4 bg-white rounded-xl shadow-sm border border-gray-100">
{todos.map((todo) => (
  <TodoItem key={todo.id} todo={todo} />
))}
</div>
)</TodoList>

// Todo Form Component
function TodoForm({ onSubmit }: { onSubmit: (e: React.FormEvent) => void }) {
const [inputValue, setInputValue] = useState("")

return (
<form className="flex gap-2 p-4 bg-white rounded-xl shadow-sm border border-gray-100 mb-6 items-center w-full" onSubmit={onSubmit}>
<input
  type="text"
  placeholder="What needs to be done?"
value={inputValue}
onChange={(e) => setInputValue(e.target.value)}
className="flex-grow p-3 border border-gray-200 rounded-lg focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none transition duration-150"
required
/>
<button
  type="submit"
className="px-6 py-3 text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg shadow-md transform hover:-translate-y-0.5 active:scale-[0.98] focus:ring-2 focus:ring-indigo-200 transition duration-150"
disabled={inputValue.trim() === ""}
>
  Add Task
</button>
</button>
</form>
)}

// Main App Component
function App() {
const [todos, setTodos] = useState<TodoItem[]>([])
const api = useApi<{ id: number; text: string; completed: boolean }>("/api/todos")

useEffect(() => {
  fetchTodos().then(setTodos)
})

const fetchTodos = async () => {
  try {
  const res = await api.get<TodoItem[]>("/api/todos")
  return res.data
}

const createTodo = async (text: string) => {
if (!text) return
try {
await api.post<TodoItem>("/api/todos", { text })
setTodos(prev => [...prev, { id: Date.now(), text, completed: false }])
} catch (e) {
  console.error("Failed to create todo:", e)
}

const toggleTodo = async (id: number) => {
if (!id) return
try {
await api.put<TodoItem>(`/api/todos/${id}`, { id, text: todo.text, completed: !todo.completed })
setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))
} catch (e) {
  console.error("Failed to toggle todo:", e)
}

const deleteTodo = async (id: number) => {
try {
await api.delete(`/api/todos/${id}`)
 setTodos(prev => prev.filter(t => t.id !== id))
} catch (e) {
  console.error("Failed to delete todo:", e)
}

return (
<div className="min-h-screen bg-gray-50">
<header className="bg-white shadow sticky top-0 z-10 py-6 px-4 sm:px-8">
<h1 className="text-3xl font-extrabold text-indigo-700 tracking-tight">Todo List</h1>
</header>

<main className="container mx-auto max-w-2xl pt-10 pb-12">
{todos.length === 0 ? (
<div className="p-8 bg-white rounded-2xl shadow-lg border border-gray-50">
  <h2 className="text-3xl font-bold text-indigo-700 mb-4">You're all caught up!</h2>
<p className="text-gray-600 max-w-md mx-auto">No tasks left to tackle. Time for a break?</p>
</div>
) : (
<section className="max-w-xl mx-auto mb-12">
<TodoForm onSubmit={handleSubmit} />
<TodoList todos={todos} />
</section>

<footer className="mt-16 border-t border-gray-100 pt-8 pb-4 text-center text-sm text-gray-500">
  &copy; {new Date().getFullYear()} Todo List. Built with Vite, React & SQLite.
</footer>
</main>
</div>
)
}

// Root component that wraps App for global styles and providers
export default function App() {
return (
<div className="min-h-screen antialiased font-sans">
<App />
)}

